ps.pstext:
var op : SystemHintOp;

var stream : boolean;
var priority : boolean;
case CRm::op2 of
    when '0000 000' => op = SystemHintOp_NOP;
    when '0000 001' => op = SystemHintOp_YIELD;
    when '0000 010' => op = SystemHintOp_WFE;
    when '0000 011' => op = SystemHintOp_WFI;
    when '0000 100' => op = SystemHintOp_SEV;
    when '0000 101' => op = SystemHintOp_SEVL;
    when '0000 110' =>
        if !IsFeatureImplemented(FEAT_DGH) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_DGH;
    when '0000 111' => See("XPACLRI");
    when '0001 xxx' =>
        case op2 of
            when '000' => See("PACIA1716");
            when '010' => See("PACIB1716");
            when '100' => See("AUTIA1716");
            when '110' => See("AUTIB1716");
            otherwise => EndOfDecode(Decode_NOP);
        end;
    when '0010 000' =>
        if !IsFeatureImplemented(FEAT_RAS) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_ESB;
    when '0010 001' =>
        if !IsFeatureImplemented(FEAT_SPE) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_PSB;
    when '0010 010' =>
        if !IsFeatureImplemented(FEAT_TRF) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_TSB;
    when '0010 011' =>
        if !IsFeatureImplemented(FEAT_GCS) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_GCSB;
    when '0010 100' =>
        op = SystemHintOp_CSDB;
    when '0010 110' =>
        if !IsFeatureImplemented(FEAT_CLRBHB) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_CLRBHB;
    when '0011 xxx' =>
        case op2 of
            when '000' => See("PACIAZ");
            when '001' => See("PACIASP");
            when '010' => See("PACIBZ");
            when '011' => See("PACIBSP");
            when '100' => See("AUTIAZ");
            when '101' => See("AUTIASP");
            when '110' => See("AUTIBZ");
            when '111' => See("AUTIBSP");
        end;
    when '0100 xx0' =>
        if !IsFeatureImplemented(FEAT_BTI) then EndOfDecode(Decode_NOP); end;

        // Check branch target compatibility between BTI instruction and PSTATE.BTYPE
        SetBTypeCompatible(BTypeCompatible_BTI(op2[2:1]));
        op = SystemHintOp_BTI;
    when '0100 111' => See("PACM");
    when '0101 000' =>
        if !IsFeatureImplemented(FEAT_CHK) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_CHKFEAT;
    when '0110 00x' =>
        if !IsFeatureImplemented(FEAT_PCDPHINT) then EndOfDecode(Decode_NOP); end;
        stream = op2[0] == '1';
        op = SystemHintOp_STSHH;
    when '0110 01x' =>
        if !IsFeatureImplemented(FEAT_CMH) then EndOfDecode(Decode_NOP); end;
        priority = op2[0] == '1';

        op = SystemHintOp_SHUH;
    when '0110 100' =>
        if !IsFeatureImplemented(FEAT_CMH) then EndOfDecode(Decode_NOP); end;
        op = SystemHintOp_STCPH;
    otherwise => EndOfDecode(Decode_NOP);
end;

case op of
    when SystemHintOp_YIELD =>
        Hint_Yield();

    when SystemHintOp_DGH =>
        Hint_DGH();

    when SystemHintOp_WFE =>
        Hint_WFE();

    when SystemHintOp_WFI =>
        Hint_WFI();

    when SystemHintOp_SEV =>
        SendEvent();

    when SystemHintOp_SEVL =>
        SendEventLocal();

    when SystemHintOp_ESB =>
        SynchronizeErrors();
        AArch64_ESBOperation();
        if PSTATE.EL IN {EL0, EL1} && EL2Enabled() then
            AArch64_vESBOperation();
        elsif IsFeatureImplemented(FEAT_E3DSE) && PSTATE.EL != EL3 then
            AArch64_dESBOperation();
        end;
        TakeUnmaskedSErrorInterrupts();

    when SystemHintOp_PSB =>
        if IsFeatureImplemented(FEAT_FGT) && IsFeatureImplemented(FEAT_SPEv1p5) then
            let trap_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                            !IsInHost() &&
                                            (!HaveEL(EL3) || SCR_EL3().FGTEn == '1') &&
                                            HFGITR_EL2().PSBCSYNC == '1');
            if trap_to_el2 then
                // to be renamed
                var except : ExceptionRecord = ExceptionSyndrome(Exception_LDST64BTrap);
                except.syndrome.iss = 0x3[24:0];
                let preferred_exception_return : bits(64) = ThisInstrAddr{}();
                let vect_offset : integer = 0x0;
                AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
            end;
        end;

        ProfilingSynchronizationBarrier();

    when SystemHintOp_TSB =>
        if IsFeatureImplemented(FEAT_FGT2) && IsFeatureImplemented(FEAT_TRBEv1p1) then
            let trap_to_el2 : boolean = (PSTATE.EL IN {EL0, EL1} && EL2Enabled() &&
                                            !IsInHost() &&
                                            (!HaveEL(EL3) || SCR_EL3().FGTEn2 == '1') &&
                                            HFGITR2_EL2().TSBCSYNC == '1');
            if trap_to_el2 then
                // to be renamed
                var except : ExceptionRecord = ExceptionSyndrome(Exception_LDST64BTrap);
                except.syndrome.iss = 0x4[24:0];
                let preferred_exception_return : bits(64) = ThisInstrAddr{}();
                let vect_offset : integer = 0x0;
                AArch64_TakeException(EL2, except, preferred_exception_return, vect_offset);
            end;
        end;

        TraceSynchronizationBarrier();

    when SystemHintOp_GCSB =>
        GCSSynchronizationBarrier();

    when SystemHintOp_CHKFEAT =>
        X{64}(16) = AArch64_ChkFeat(X{64}(16));

    when SystemHintOp_CSDB =>
        ConsumptionOfSpeculativeDataBarrier();

    when SystemHintOp_CLRBHB =>
        Hint_CLRBHB();

    when SystemHintOp_BTI =>
        SetBTypeNext('00');

    when SystemHintOp_STSHH =>
        Hint_StoreShared(stream);

    when SystemHintOp_SHUH =>
        Hint_SharedUpdate(priority);

    when SystemHintOp_STCPH =>
        Hint_StoreConcurrentPriority();

    when SystemHintOp_NOP =>
        return; // Do nothing

    otherwise =>
        unreachable;
end;
